import React from "react";
import "./Banner.css";

import { Swiper, SwiperSlide } from "swiper/react";
import { Autoplay, Pagination, Navigation } from "swiper/modules";

import "swiper/css";
import "swiper/css/pagination";
import "swiper/css/navigation";

function Banner() {
  return (
    <div className="banner">

      <Swiper
        modules={[Autoplay, Pagination, Navigation]}
        spaceBetween={10}
        slidesPerView={1}
        autoplay={{
          delay: 2500,
          disableOnInteraction: false,
        }}
        pagination={{ clickable: true }}
        navigation={true}
        loop={true}
      >

        {/* Slide 1 */}
        <SwiperSlide>
          <img
            src="https://rukminim2.flixcart.com/fk-p-flap/1600/270/image/5b3f3b9cfdc8f5e4.jpg"
            alt="Sale Banner 1"
          />
        </SwiperSlide>

        {/* Slide 2 */}
        <SwiperSlide>
          <img
            src="https://rukminim2.flixcart.com/fk-p-flap/1600/270/image/4d9a8f62b86c7b5e.jpg"
            alt="Sale Banner 2"
          />
        </SwiperSlide>

        {/* Slide 3 */}
        <SwiperSlide>
          <img
            src="https://rukminim2.flixcart.com/fk-p-flap/1600/270/image/7d64a0b4fdd5f1a7.jpg"
            alt="Sale Banner 3"
          />
        </SwiperSlide>

      </Swiper>

    </div>
  );
}

export default Banner;
